from typing import Optional, Dict, Any

import requests
from zeep import Client, Settings
from zeep.transports import Transport
from zeep.plugins import HistoryPlugin
from zeep.exceptions import Fault


def prompt_nonempty(prompt: str) -> str:
    while True:
        v = input(prompt).strip()
        if v:
            return v


def prompt_optional(prompt: str) -> Optional[str]:
    v = input(prompt).strip()
    return v if v else None


def build_client(wsdl_url: str, username: Optional[str], password: Optional[str], timeout: int = 30) -> Client:
    session = requests.Session()
    if username is not None and password is not None:
        session.auth = (username, password)

    transport = Transport(session=session, timeout=timeout)
    settings = Settings(strict=False, xml_huge_tree=True)
    history = HistoryPlugin()
    client = Client(wsdl=wsdl_url, transport=transport, settings=settings, plugins=[history])
    return client


def call_policy_lookup(
    client: Client,
    service_name: Optional[str],
    port_name: Optional[str],
    operation: str,
    policy_number: str,
    customer_name: str,
    extra_params: Optional[Dict[str, Any]] = None,
) -> Any:
    if service_name and port_name:
        binding = client.bind(service_name, port_name)
        op = getattr(binding.service, operation)
    else:
        op = getattr(client.service, operation)

    params = {
        "PolicyNumber": policy_number,
        "CustomerName": customer_name,
    }
    if extra_params:
        params.update(extra_params)

    return op(**params)


